 * middleA:
 *	Play middle A (on the relays - yea!)
 *********************************************************************************
 */

static void middleA (void)
{
  unsigned int next ;

  for (;;)
  {
    next = micros () + 1136 ;
    digitalWrite (PIFACE + 0, 0)  ;
    digitalWrite (PIFACE + 1, 0)  ;
    while (micros () < next)
      delayMicroseconds (1) ;

    next = micros () + 1137 ;
    digitalWrite (PIFACE + 0, 1)  ;
    digitalWrite (PIFACE + 1, 1)  ;
    while (micros () < next)
      delayMicroseconds (1) ;

  }
}


