      while (digitalRead (PWM_UP) == LOW)
	delay (5) ;
    }

    if (digitalRead (PWM_DOWN) == LOW)
    {
      pwmValue -= 10 ;
      if (pwmValue < 0)
	pwmValue = 0 ;

      softPwmWrite (PWM_OUT_PIN, pwmValue) ;
      printf ("PWM -> %3d\n", pwmValue) ;

      while (digitalRead (PWM_DOWN) == LOW)
	delay (5) ;
    }

    delay (5) ;
  }

  return 0 ;
}

