   gpio_pin = GPIO_READ;

   DelayMicrosecondsNoSleep(420);

   gpio_pin &= PinMask;

   if(gpio_pin ==0) return 1;

   BadSensor|= gpio_pin;
   return 0;
}



void WriteByte(unsigned char value)
{
