           SetInputMode();
           usleep(60);

        }
        else
        {
           DelayMicrosecondsNoSleep(60);
           SetInputMode();
           usleep(1);
        }
      Mask*=2;
      DelayMicrosecondsNoSleep(60);
    }


   usleep(100);
}


